import React, { Component } from "react";
import classes from './Productscards.module.css';
import Products from './Products';

import img1 from '../../Assets/corepnproduct.webp';
import img2 from '../../Assets/trc-GwSjNOuA8-transformed.png';
import img3 from '../../Assets/grindingworks-transformed.png';
import img4 from '../../Assets/carbidedead-transformed.png';
import img5 from '../../Assets/hsscutter-zeNIj-3wqC-transformed.png';
import img6 from '../../Assets/valveseatadaptedr-transformed.png';
import img7 from '../../Assets/hobbing-transformed (1).png';
import img8 from '../../Assets/precisioncomp-transformed.png';
import img9 from '../../Assets/restpad-transformed.png';
import img10 from '../../Assets/industrialcutter-A1V0qoA-z-transformed.png';



const Productscards=()=>{
return (
    <div className={classes.hold}>
        <h3 className={classes.head}>OUR PRODUCTS</h3>
     
            <div className={classes.row}>

            <div>
                <Products img={img1} head='CORE PINS' text='READ MORE'></Products>
            </div>
            <div>
                <Products img={img2} head='TOTAL TOOM COMPONENT'text='READ MORE' ></Products>
            </div>
            <div>
                <Products img={img3} head='GRINDING WORKS' text='READ MORE'></Products>
            </div>
            <div>
                <Products img={img4} head='CARBIDE DEAD CENTERS' text='READ MORE'></Products>
            </div>
            <div>
                <Products img={img5} head='CARBIDE AND HSS CUTTERS RESHARPENING' text='READ MORE'></Products>
            </div>
            
            </div>


            <div className={classes.row}>

            <div>
                <Products img={img6} head='VALVE SEAT ADAPTER' text='READ MORE' ></Products>
            </div>
            <div>
                <Products img={img7} head='HOBBING FIXTURE SLEEVES' text='READ MORE' ></Products>
            </div>
            <div>
                <Products img={img8} head='PERCISION COMPONENT' text='READ MORE'></Products>
            </div>
            <div>
                <Products img={img9} head='REST PAD' text='READ MORE'></Products>
            </div>
            <div>
                <Products img={img10} head='INDUSTRIAL CUTTERS' text='READ MORE' ></Products>
            </div>
            </div>

    </div>
)
};

export default Productscards;
